option.value:
plugins {
    id 'java'
    id 'org.springframework.boot' version '4.0.6'
    id 'io.spring.dependency-management' version '1.1.7'
}

group = 'com.trung'
version = '0.0.1-SNAPSHOT'
description = 'batch-service'

java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(17)
    }
}

repositories {
    mavenCentral()
}

ext {
    set('springCloudVersion', "2025.1.1")
}

dependencies {
    implementation 'org.springframework.boot:spring-boot-starter-data-jpa'
    implementation 'org.springframework.boot:spring-boot-starter-webmvc'
    implementation 'org.springframework.cloud:spring-cloud-starter-config'
    implementation 'org.springframework.boot:spring-boot-starter-actuator'
    implementation 'org.springframework.boot:spring-boot-starter-kafka'
    testImplementation 'org.springframework.kafka:spring-kafka-test'
    compileOnly 'org.projectlombok:lombok'
    runtimeOnly 'org.postgresql:postgresql'
    runtimeOnly 'com.h2database:h2'
    annotationProcessor 'org.projectlombok:lombok'
    testImplementation 'org.springframework.boot:spring-boot-starter-data-jpa-test'
    testImplementation 'org.springframework.boot:spring-boot-starter-webmvc-test'
    testCompileOnly 'org.projectlombok:lombok'
    testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
    testAnnotationProcessor 'org.projectlombok:lombok'
    implementation 'com.fasterxml.jackson.datatype:jackson-datatype-jsr310'
}

dependencyManagement {
    imports {
        mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudVersion}"
    }
}

tasks.named('test') {
    useJUnitPlatform()
}

package com.trung.batchservice;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.scheduling.annotation.EnableScheduling;

@SpringBootApplication
@EnableScheduling
public class BatchServiceApplication {

    public static void main(String[] args) {
        SpringApplication.run(BatchServiceApplication.class, args);
    }

}

package com.trung.batchservice.entity;

import jakarta.persistence.*;
import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.NoArgsConstructor;
import java.time.LocalDate;

@Entity
@Table(name = "medicines")
@Data
@AllArgsConstructor
@NoArgsConstructor
public class Medicine {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private String medicineId;
    private String medicineName;
    private Integer quantity;
    private LocalDate expiryDate;
    private String status;  // AVAILABLE, EXPIRING_SOON, EXPIRED, NEED_IMPORT
}

package com.trung.batchservice.event;

import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.NoArgsConstructor;
import java.time.LocalDateTime;
import java.util.List;

@Data
@AllArgsConstructor
@NoArgsConstructor
public class ExpirationWarningEvent {
    private String eventId;
    private Long expiringMedicineCount;
    private List<MedicineInfo> expiringMedicines;
    private LocalDateTime timestamp;
    private String message;

    @Data
    @AllArgsConstructor
    @NoArgsConstructor
    public static class MedicineInfo {
        private String medicineId;
        private String medicineName;
        private Integer quantity;
        private String expiryDate;
    }
}

package com.trung.batchservice.repository;

import com.trung.batchservice.entity.Medicine;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;
import java.time.LocalDate;
import java.util.List;

@Repository
public interface MedicineRepository extends JpaRepository<Medicine, Long> {
    // Tìm các thuốc sắp hết hạn (trong 30 ngày tới)
    @Query("SELECT m FROM Medicine m WHERE m.expiryDate BETWEEN CURRENT_DATE AND CURRENT_DATE + 30 AND m.status != 'EXPIRED'")
    List<Medicine> findExpiringMedicines();

    // Tìm các thuốc đã hết hạn
    @Query("SELECT m FROM Medicine m WHERE m.expiryDate < CURRENT_DATE AND m.status != 'EXPIRED'")
    List<Medicine> findExpiredMedicines();
}

package com.trung.batchservice.scheduler;

import com.trung.batchservice.service.ExpirationBatchService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

@Component
@Slf4j
@RequiredArgsConstructor
public class ExpirationCheckScheduler {
    private final ExpirationBatchService expirationBatchService;

    /**
     * Scheduled task để kiểm tra thuốc sắp hết hạn
     * Mặc định chạy mỗi 60 giây (60000 ms)
     * Bạn có thể thay đổi thời gian trong application.yaml
     */
    @Scheduled(fixedRateString = "${scheduling.expiration-check-interval:60000}", initialDelay = 10000)
    public void scheduleExpirationCheck() {
        try {
            log.debug("⏱️ Bắt đầu scheduled task kiểm tra thuốc sắp hết hạn");
            expirationBatchService.checkAndNotifyExpiringMedicines();
        } catch (Exception e) {
            log.error("❌ Lỗi trong scheduled task kiểm tra thuốc sắp hết hạn", e);
        }
    }
}
